193: 														  estate, eflags);
194: 			break;
195: 
196: 		case T_BitmapAnd:
197: 			result = (PlanState *) ExecInitBitmapAnd((BitmapAnd *) node,
198: 													 estate, eflags);
199: 			break;
200: 
201: 		case T_BitmapOr:
202: 			result = (PlanState *) ExecInitBitmapOr((BitmapOr *) node,
203: 													estate, eflags);
204: 			break;
